// ELAB GDPR Service — n8n Code Node V4
// Andrea Marro — 17/02/2026
// Schema aligned to Notion DB '🔒 GDPR Requests'
// Uses this.helpers.httpRequest (no fetch, no returnFullResponse)

const NOTION_TOKEN = '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';
const NOTION_DB = 'e2e0c070301b4813a7c5378a2d46758a';
const NOTION_API = 'https://api.notion.com/v1';

// Robust body extraction: webhook v2 wraps POST body under .body
const raw = $input.first().json;
const body = raw.body || raw;
const action = body.action || 'unknown';

// --- HTTP helper (n8n sandbox — NO fetch, NO returnFullResponse) ---
async function notionRequest(method, path, data) {
  const options = {
    method,
    url: NOTION_API + path,
    headers: {
      'Authorization': 'Bearer ' + NOTION_TOKEN,
      'Notion-Version': '2022-06-28',
      'Content-Type': 'application/json'
    }
  };
  if (data) options.body = data;
  return await this.helpers.httpRequest(options);
}

async function notionCreate(properties) {
  return await notionRequest.call(this, 'POST', '/pages', {
    parent: { database_id: NOTION_DB },
    properties
  });
}

async function notionQuery(filter) {
  return await notionRequest.call(this, 'POST', '/databases/' + NOTION_DB + '/query', { filter });
}

async function notionUpdate(pageId, properties) {
  return await notionRequest.call(this, 'PATCH', '/pages/' + pageId, { properties });
}

// --- Notion property helpers ---
const textProp = (v) => ({ rich_text: [{ text: { content: String(v || '') } }] });
const titleProp = (v) => ({ title: [{ text: { content: String(v || '') } }] });
const selectProp = (v) => ({ select: { name: String(v || '') } });
const emailProp = (v) => ({ email: String(v || '') });
const numProp = (v) => ({ number: Number(v) || 0 });
const checkProp = (v) => ({ checkbox: Boolean(v) });
const dateProp = () => ({ date: { start: new Date().toISOString() } });

// --- Token generator ---
function makeToken() {
  const chars = 'abcdefghijklmnopqrstuvwxyz0123456789';
  let token = 'tok_';
  for (let i = 0; i < 24; i++) {
    token += chars[Math.floor(Math.random() * chars.length)];
  }
  return token;
}

// --- Action mapping (Italian select options) ---
const TIPO_MAP = {
  'delete': 'Eliminazione Dati',
  'export': 'Esportazione Dati',
  'correct': 'Rettifica Dati',
  'revoke': 'Revoca Consenso',
  'parental-consent': 'Consenso Parentale',
  'verify-parental-consent': 'Verifica Parentale'
};

let result = { success: false, action };

try {
  if (action === 'delete') {
    const page = await notionCreate.call(this, {
      'Name': titleProp('DEL-' + Date.now()),
      'Tipo': selectProp(TIPO_MAP[action]),
      'User ID': textProp(body.userId),
      'Motivo': textProp(body.reason),
      'Stato': selectProp('Ricevuta'),
      'Data Richiesta': dateProp()
    });
    result = { success: true, action, pageId: page.id, message: 'Richiesta eliminazione registrata' };

  } else if (action === 'parental-consent') {
    const token = makeToken();
    const page = await notionCreate.call(this, {
      'Name': titleProp('PC-' + Date.now()),
      'Tipo': selectProp(TIPO_MAP[action]),
      'Dettagli': textProp('Minore: ' + (body.childName || '')),
      'Et\u00e0 Minore': numProp(body.childAge),
      'Email Genitore': emailProp(body.parentEmail),
      'Nome Genitore': textProp(body.parentName),
      'Metodo Consenso': selectProp(body.consentMethod === 'firma' ? 'Firma Digitale' : 'Email'),
      'COPPA': checkProp(true),
      'Stato': selectProp('In Attesa Verifica'),
      'Token Verifica': textProp(token),
      'Data Richiesta': dateProp()
    });
    result = { success: true, action, pageId: page.id, token, message: 'Richiesta consenso parentale registrata' };

  } else if (action === 'export') {
    const page = await notionCreate.call(this, {
      'Name': titleProp('EXP-' + Date.now()),
      'Tipo': selectProp(TIPO_MAP[action]),
      'User ID': textProp(body.userId),
      'Email': emailProp(body.email || ''),
      'Stato': selectProp('Ricevuta'),
      'Data Richiesta': dateProp()
    });
    result = { success: true, action, pageId: page.id, message: 'Richiesta esportazione registrata' };

  } else if (action === 'revoke') {
    const page = await notionCreate.call(this, {
      'Name': titleProp('REV-' + Date.now()),
      'Tipo': selectProp(TIPO_MAP[action]),
      'User ID': textProp(body.userId),
      'Stato': selectProp('Completata'),
      'Data Richiesta': dateProp(),
      'Data Completamento': dateProp()
    });
    result = { success: true, action, pageId: page.id, message: 'Consenso revocato' };

  } else if (action === 'verify-parental-consent') {
    const qData = await notionQuery.call(this, {
      property: 'Token Verifica',
      rich_text: { equals: body.token || '' }
    });
    const results = qData.results || [];
    if (results.length > 0) {
      const pageId = results[0].id;
      await notionUpdate.call(this, pageId, {
        'Stato': selectProp('Completata'),
        'Data Completamento': dateProp()
      });
      result = { success: true, action, verified: true, message: 'Consenso verificato' };
    } else {
      result = { success: false, action, verified: false, message: 'Token non valido' };
    }

  } else if (action === 'correct') {
    const page = await notionCreate.call(this, {
      'Name': titleProp('COR-' + Date.now()),
      'Tipo': selectProp(TIPO_MAP[action]),
      'User ID': textProp(body.userId),
      'Dettagli': textProp(JSON.stringify(body.corrections)),
      'Stato': selectProp('Ricevuta'),
      'Data Richiesta': dateProp()
    });
    result = { success: true, action, pageId: page.id, message: 'Richiesta rettifica registrata' };

  } else {
    result = { success: false, action, message: 'Azione non riconosciuta: ' + action };
  }
} catch (error) {
  result = { success: false, action, error: error.message };
}

return [{ json: result }];
